export interface Trigram {
  cn: string
  vn: string
  pinyin: string
  nature: string
  en: string
  el: 'metal' | 'fire' | 'wood' | 'water' | 'earth'
  lines: [number, number, number] // 1=yang, 0=yin, index 0=top line
  family: string
}

export interface Hexagram {
  num: number
  cn: string
  pinyin: string
  vn: string
  vnFull: string
  en: string
  upperTriIdx: number
  lowerTriIdx: number
  description: string
}

export interface IChingEntry {
  judgment: { vn: string; en: string }
  image: { vn: string; en: string }
  lines: { vn: string; en: string }[]
}

