export function getHexLines(upperIdx: number, lowerIdx: number): number[] {
  return [...TRIGRAMS[upperIdx].lines, ...TRIGRAMS[lowerIdx].lines]
}

export function getHexElement(upperIdx: number): string {
  return TRIGRAMS[upperIdx].el
}

export function buildGridMatrix(): (Hexagram | undefined)[][] {
  const matrix: (Hexagram | undefined)[][] = []
  for (let i = 0; i < 8; i++) {
    matrix[i] = []
    for (let j = 0; j < 8; j++) {
      matrix[i][j] = HEXAGRAMS.find(h => h.upperTriIdx === i && h.lowerTriIdx === j)
    }
  }
  return matrix
}

